"""stl_validator_improved.py -- Improved STL validation tool.

Supports both ASCII and Binary STL files.
Checks:
  - Triangle count (minimum viable solid)
  - Surface area
  - Volume (using divergence theorem)
  - Manifold integrity (open edges AND non-manifold edges with >2 triangles)
  - Degenerate triangles (zero area)
  - Duplicate triangles
  - Face normal consistency (inverted normals)
  - Manufacturing suitability summary
"""
import json
import math
import struct
import sys


# ---------------------------------------------------------------------------
# Math helpers
# ---------------------------------------------------------------------------

def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )

def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])

def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]

def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)

def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0] / m, v[1] / m, v[2] / m)

def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))

def _signed_volume_contribution(v1, v2, v3):
    """Signed volume contribution of a triangle via divergence theorem."""
    return _dot(v1, _cross(v2, v3)) / 6.0


# ---------------------------------------------------------------------------
# Parsers
# ---------------------------------------------------------------------------

def _is_binary_stl(path: str) -> bool:
    """Heuristic: check if STL is binary."""
    with open(path, 'rb') as f:
        header = f.read(80)
        if len(header) < 80:
            return False
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            return False
        triangle_count = struct.unpack('<I', count_bytes)[0]
        # Binary STL: 80 header + 4 count + 50 bytes per triangle
        expected_size = 80 + 4 + triangle_count * 50
        f.seek(0, 2)  # seek to end
        actual_size = f.tell()
        if actual_size == expected_size and triangle_count > 0:
            return True
        # Also check if first 5 bytes are NOT 'solid' (some binary files start with 'solid')
        # Use size as primary heuristic
        if actual_size == expected_size:
            return True
    # Check if it starts with 'solid' keyword
    with open(path, 'r', errors='replace') as f:
        first = f.read(256)
        if first.lstrip().startswith('solid'):
            return False
    return True


def _parse_binary_stl(path: str) -> tuple:
    """Parse binary STL. Returns (triangles, issues).
    triangles = list of (declared_normal, [v1, v2, v3])
    """
    issues = []
    triangles = []
    with open(path, 'rb') as f:
        header = f.read(80)
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            issues.append("Binary STL: truncated file (missing triangle count)")
            return triangles, issues
        triangle_count = struct.unpack('<I', count_bytes)[0]
        for i in range(triangle_count):
            data = f.read(50)
            if len(data) < 50:
                issues.append(f"Binary STL: truncated at triangle {i}")
                break
            nx, ny, nz = struct.unpack('<fff', data[0:12])
            v1 = struct.unpack('<fff', data[12:24])
            v2 = struct.unpack('<fff', data[24:36])
            v3 = struct.unpack('<fff', data[36:48])
            # attribute byte count = data[48:50] (ignored)
            triangles.append(((nx, ny, nz), [v1, v2, v3]))
    return triangles, issues


def _parse_ascii_stl(path: str) -> tuple:
    """Parse ASCII STL. Returns (triangles, issues)."""
    issues = []
    triangles = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue
        i += 1
    return triangles, issues


# ---------------------------------------------------------------------------
# Main validation
# ---------------------------------------------------------------------------

def parse_stl(path: str) -> dict:
    issues = []

    # Detect format and parse
    try:
        binary = _is_binary_stl(path)
    except OSError as e:
        return {"valid": False, "error": str(e), "issues": [str(e)]}

    stl_format = "binary" if binary else "ascii"
    if binary:
        triangles, parse_issues = _parse_binary_stl(path)
    else:
        triangles, parse_issues = _parse_ascii_stl(path)
    issues.extend(parse_issues)

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "format": stl_format,
            "triangle_count": 0,
            "surface_area": 0.0,
            "volume": 0.0,
            "issues": issues,
        }

    # Minimum triangle count check
    if len(triangles) < 4:
        issues.append(
            f"Too few triangles ({len(triangles)}) to form a valid closed solid (minimum 4)"
        )

    # Degenerate triangle check
    degenerate_count = 0
    degenerate_indices = set()
    for idx, (_, verts) in enumerate(triangles):
        area = _triangle_area(*verts)
        if area < 1e-10:
            degenerate_count += 1
            degenerate_indices.add(idx)
    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")

    # Duplicate triangle check
    seen_triangles = {}
    duplicate_count = 0
    for idx, (_, verts) in enumerate(triangles):
        rounded = tuple(sorted(tuple(round(x, 6) for x in v) for v in verts))
        if rounded in seen_triangles:
            duplicate_count += 1
        else:
            seen_triangles[rounded] = idx
    if duplicate_count > 0:
        issues.append(f"Mesh has {duplicate_count} duplicate triangle(s)")

    # Manifold check: every edge must be shared by exactly 2 triangles
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    nonmanifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)

    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")
    if nonmanifold_edges > 0:
        issues.append(
            f"Mesh has {nonmanifold_edges} non-manifold edge(s) (shared by >2 triangles)"
        )

    # Normal consistency check: compare declared normal against winding-order normal
    inverted_count = 0
    for idx, (declared_normal, verts) in enumerate(triangles):
        if idx in degenerate_indices:
            continue  # skip degenerate triangles
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        if _magnitude(cross) < 1e-10:
            continue
        winding_normal = _normalize(cross)
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            continue  # zero declared normal — skip (some exporters emit 0,0,0)
        similarity = _dot(_normalize(declared_normal), winding_normal)
        if similarity < -0.99:
            inverted_count += 1
    if inverted_count > 0:
        issues.append(
            f"{inverted_count} face normal(s) are inverted relative to winding order"
        )

    # Surface area
    surface_area = sum(
        _triangle_area(*verts)
        for idx, (_, verts) in enumerate(triangles)
        if idx not in degenerate_indices
    )

    # Volume (signed, via divergence theorem)
    signed_volume = sum(
        _signed_volume_contribution(*verts)
        for idx, (_, verts) in enumerate(triangles)
        if idx not in degenerate_indices
    )
    volume = abs(signed_volume)

    # If volume is near-zero for a closed mesh, flag it
    if open_edges == 0 and nonmanifold_edges == 0 and volume < 1e-10:
        issues.append("Mesh appears to have zero volume despite being closed")

    return {
        "valid": len(issues) == 0,
        "format": stl_format,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "volume": round(volume, 6),
        "issues": issues,
    }


if __name__ == '__main__':
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    print(json.dumps(parse_stl(sys.argv[1])))
